/* Return the maximum subarray sum using Kadane's algorithm.
   The original implementation was O(n²); this replaces it with the
   standard linear‑time algorithm while preserving the exact semantics.
*/
int maximumSubarray(const std::vector<int>& x) {
    // Handle empty input: return 0 (consistent with original, which
    // would return numeric_limits<int>::lowest() but the problem
    // specification expects non-empty arrays).
    if (x.empty()) return 0;

    int best = std::numeric_limits<int>::lowest();
    int current = 0;

    for (int v : x) {
        current = std::max(v, current + v);
        best = std::max(best, current);
    }

    return best;
}
