/* Return the value of the smallest odd number in the vector x.
   Examples:
   input: [7, 9, 5, 2, 8, 16, 4, 1]
   output: 1
   input: [8, 36, 7, 2, 11]
   output: 7
*/
inline int smallestOdd(const std::vector<int>& x)
{
    const int sentinel = std::numeric_limits<int>::max();
    int min_odd = sentinel;

    /* Parallel reduction over the elements.
       The reduction variable is initialized to `sentinel` so that
       the combined result is correct even when no odd number is
       present (the function then returns `INT_MAX`). */
#pragma omp parallel for reduction(min : min_odd)
    for (std::size_t i = 0; i < x.size(); ++i)
    {
        int val = x[i];
        if ((val & 1) && val < min_odd) /* odd and smaller than current minimum */
            min_odd = val;
    }

    return min_odd;
}
