/* Compute the prefix sum array of the vector x and return its sum.
   Example:
   input: [-7, 2, 1, 9, 4, 8]
   output: 15
*/
int64_t sumOfPrefixSum(const std::vector<int64_t> &x) {
    const size_t n = x.size();
    if (n == 0) return 0;

    int64_t total = 0;
#pragma omp parallel for reduction(+:total) schedule(static)
    for (size_t i = 0; i < n; ++i) {
        // Each element contributes x[i] to all subsequent prefix sums, including itself.
        // Number of prefix sums that include x[i] is (n - i).
        total += x[i] * static_cast<int64_t>(n - i);
    }
    return total;
}
