#pragma once
#include <vector>
#include <limits>
#include <cstddef>
#include <cstring>

/* Return the length of the shortest path from source to dest in the undirected graph defined by the adjacency matrix A.
   A is an NxN adjacency matrix stored in row-major. Assume the graph is connected. A is undirected.
*/
int shortestPathLength(const std::vector<int> &A, size_t N, int source, int dest) {
    // Use a contiguous array for visited to avoid branch mispredictions
    std::vector<char> visited(N, 0);
    // Preallocate a flat array for the BFS queue (size at most N)
    std::vector<int> que(N);
    std::vector<int> dist(N, 0);

    size_t head = 0, tail = 0;
    visited[source] = 1;
    que[tail++] = source;
    dist[source] = 0;

    while (head < tail) {
        int v = que[head++];
        int d = dist[v];
        if (v == dest) return d;

        // Scan all neighbours of v
        const int *row = A.data() + v * N;
        for (size_t u = 0; u < N; ++u) {
            if (row[u] && !visited[u]) {
                visited[u] = 1;
                que[tail++] = static_cast<int>(u);
                dist[u] = d + 1;
            }
        }
    }
    return std::numeric_limits<int>::max();
}
