#include <omp.h>

struct Element {
    std::size_t index;
    double value;
};

/* Compute z = alpha*x+y where x and y are sparse vectors.
 * The result is accumulated into vector z which must be pre‑initialized
 * with the appropriate size (all entries set to 0 before the call).
 */
inline void sparseAxpy(double alpha,
                       const std::vector<Element>& x,
                       const std::vector<Element>& y,
                       std::vector<double>& z)
{
    std::size_t xi = 0, yi = 0;
    /* merge the two sorted lists (x and y) */
    while (xi < x.size() && yi < y.size()) {
        if (x[xi].index < y[yi].index) {
            // only in x
            #pragma omp atomic
            z[x[xi].index] += alpha * x[xi].value;
            ++xi;
        }
        else if (x[xi].index > y[yi].index) {
            // only in y
            #pragma omp atomic
            z[y[yi].index] += y[yi].value;
            ++yi;
        }
        else {
            // in both
            #pragma omp atomic
            z[x[xi].index] += alpha * x[xi].value + y[yi].value;
            ++xi;
            ++yi;
        }
    }
    /* remaining elements in x */
    while (xi < x.size()) {
        #pragma omp atomic
        z[x[xi].index] += alpha * x[xi].value;
        ++xi;
    }
    /* remaining elements in y */
    while (yi < y.size()) {
        #pragma omp atomic
        z[y[yi].index] += y[yi].value;
        ++yi;
    }
}
