```cpp
#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Efficient sparse–sparse multiplication
 * Y = A * X   (Y is dense, row‑major)
 *
 * A  : M x K  COO,   X : K x N  COO,  Y : M x N dense
 *
 * The routine builds a hash map of X indexed by its row,
 * then parallelises the outer loop over the entries of A.
 * Atomic updates are used to preserve the exact semantics
 * of the sequential algorithm while enabling full
 * multi‑thread execution on a modern x86‑64 system.
 */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double> &Y,
          size_t M, size_t K, size_t N)
{
    Y.assign(M * N, 0.0);

    /* build a hash map: row → list of (col, value) of X */
    std::unordered_map<size_t, std::vector<COOElement>> x_by_row;
    x_by_row.reserve(X.size() * 2);
    for (auto const& e : X) {
        x_by_row[e.row].push_back(e);
    }

    /* parallel over non‑zeros of A */
#pragma omp parallel for schedule(dynamic)
    for (size_t ia = 0; ia < A.size(); ++ia) {
        const auto& a = A[ia];
        auto it = x_by_row.find(a.column);
        if (it == x_by_row.end()) continue;          // no matching rows

        const auto& vec = it->second;
        size_t base_row = a.row * N;
        for (const auto& x : vec) {
            /* atomic add to preserve ordering semantics */
            double prod = a.value * x.value;
#pragma omp atomic
            Y[base_row + x.column] += prod;
        }
    }
}
