/* Count the number of cartesian points in each quadrant.
   The vector points contains a list of `Point` objects.
   Store the counts in `bins` (four elements: Q1, Q2, Q3, Q4).

   Parallelised with OpenMP: each thread accumulates counts locally
   and the results are summed at the end.
*/
void countQuadrants(std::vector<Point> const& points, std::array<size_t, 4> &bins)
{
    // initialise the output bins
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    const size_t n = points.size();
    if (n == 0)
        return;

    // Parallel processing
#pragma omp parallel
    {
        // local counts for this thread
        size_t local[4] = {0, 0, 0, 0};

        // simple loop with bounds check removed by manual indexing
#pragma omp for schedule(static)
        for (size_t i = 0; i < n; ++i)
        {
            const Point &p = points[i];
            if (p.x >= 0.0)
            {
                if (p.y >= 0.0)
                    ++local[0];   // Q1
                else
                    ++local[3];   // Q4
            }
            else
            {
                if (p.y >= 0.0)
                    ++local[1];   // Q2
                else
                    ++local[2];   // Q3
            }
        }

        // merge local counts into the global result
#pragma omp atomic
        bins[0] += local[0];
#pragma omp atomic
        bins[1] += local[1];
#pragma omp atomic
        bins[2] += local[2];
#pragma omp atomic
        bins[3] += local[3];
    }
}
