#include <omp.h>

/* Compute the prefix sum of the vector `x` into `output`.
   The result is identical to the standard inclusive_scan.
   Implementation is parallelized with OpenMP for up to 8 threads. */
inline void prefixSum(const std::vector<int64_t>& x, std::vector<int64_t>& output) {
    const std::size_t n = x.size();
    output.resize(n);
    if (n == 0) return;

    const int maxThreads = 8;
    int numThreads = std::min(maxThreads, static_cast<int>(n));
    std::vector<int64_t> blockSum(numThreads);
    std::size_t chunk = (n + numThreads - 1) / numThreads;          // ceil
    std::size_t last = n % chunk;                                  // last chunk size
    if (last == 0) last = chunk;

    /* 1) Compute partial sums per block */
    #pragma omp parallel num_threads(numThreads)
    {
        int tid = omp_get_thread_num();
        std::size_t start = tid * chunk;
        std::size_t len   = (tid == numThreads-1) ? last : chunk;
        if (start >= n) len = 0;
        if (len == 0) return;
        int64_t sum = 0;
        for (std::size_t i = start; i < start + len; ++i) {
            sum += x[i];
            output[i] = sum;
        }
        blockSum[tid] = sum;
    }

    /* 2) Compute prefix of block sums (serial – very small) */
    std::vector<int64_t> blockOff(numThreads);
    int64_t acc = 0;
    for (int i = 0; i < numThreads; ++i) {
        blockOff[i] = acc;
        acc += blockSum[i];
    }

    /* 3) Add block offsets to each block (parallel) */
    #pragma omp parallel num_threads(numThreads)
    {
        int tid = omp_get_thread_num();
        std::size_t start = tid * chunk;
        std::size_t len   = (tid == numThreads-1) ? last : chunk;
        int64_t offs = blockOff[tid];
        for (std::size_t i = start; i < start + len; ++i) {
            output[i] += offs;
        }
    }
}
