#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

// ----------------------------------------------------------------------------
// Optimised dense LU factorisation of a sparse matrix given in COO format.
// The result is written in row‑major form into L and U.
// The algorithm is unchanged – only the data layout and memory access patterns
// have been tuned for modern x86‑64 CPUs and GCC 12+ with OpenMP.
// ----------------------------------------------------------------------------
inline void luFactorize(
    const std::vector<COOElement> &A,
    std::vector<double> &L,            // size N*N, row‑major
    std::vector<double> &U,            // size N*N, row‑major
    const size_t N)
{
    // Allocate a contiguous dense scratch matrix and initialise it to zero
    std::vector<double> dense(N * N, 0.0);

    // Pack the COO entries into the dense matrix
    for (const auto &e : A)
        dense[e.row * N + e.column] = e.value;

    // Initialise L with zeros; U will be written during the loop
    std::fill(L.begin(), L.end(), 0.0);

    // ----------------------------------------------------------------------
    // Main LU factorisation – the loops are the classic Doolittle algorithm.
    // A parallelised outer loop is safe because each iteration writes only and
    // reads only rows that have already been completed.
    //
    // OpenMP:
    //     - parallelise over 'i' (outermost row)
    //     - static schedule provides good load balance for dense data
    // ----------------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        // --- Upper triangular part ---------------------------------------
        for (size_t j = i; j < N; ++j) {
            double val = dense[i * N + j];
            for (size_t k = 0; k < i; ++k)
                val -= L[i * N + k] * U[k * N + j];
            U[i * N + j] = val;
        }

        // --- Lower triangular part ---------------------------------------
        for (size_t j = 0; j < i; ++j) {
            double val = dense[i * N + j];
            for (size_t k = 0; k < j; ++k)
                val -= L[i * N + k] * U[k * N + j];
            // Division by diagonal U[j][j] (guaranteed non‑zero for valid inputs)
            L[i * N + j] = val / U[j * N + j];
        }

        // Diagonal of L is always 1
        L[i * N + i] = 1.0;
    }
}
