/* Compute one iteration of a 3‑point 1‑D Jacobi stencil on `input`.
 * Each element of `input` is averaged with its two neighbors and stored
 * in the corresponding element of `output`.  Out‑of‑bounds references
 * contribute 0.  Exact semantics of the reference implementation are
 * preserved.
 */
inline void jacobi1D(std::vector<double> const& input, std::vector<double> &output)
{
    const size_t N = input.size();
    constexpr double inv3 = 1.0 / 3.0;   // pre‑compute reciprocal
#if defined(_OPENMP)
    // Parallelise safely: each iteration is independent
    #pragma omp parallel for schedule(static)
#endif
    for (size_t i = 0; i < N; ++i) {
        double sum = input[i];
        if (i > 0)       sum += input[i - 1];
        if (i + 1 < N)   sum += input[i + 1];
        output[i] = sum * inv3;
    }
}
