#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

// ---------------------------------------------------------------------------
// Optimised DFT
// ---------------------------------------------------------------------------
//
// The function keeps the exact semantics of the reference implementation
// but adds the following performance improvements:
//   * Explicit OpenMP parallelisation of the outer loop.
//   * Pre‑computed constant 2π/N to avoid repeated division.
//   * Chunked loop schedule to balance work among the 8 threads on a
//     typical modern hardware.
//   * Use of raw pointers for direct memory access in inner loops.
//   * Avoid construction of temporary std::complex objects inside the inner loop.
// ---------------------------------------------------------------------------

inline void dft(const std::vector<double>& x, std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output.resize(N);
    const double two_pi_over_N = 2.0 * M_PI / static_cast<double>(N);

    // Work per thread is roughly equal when splitting by outer loop
    const int chunk = static_cast<int>((N + 7) / 8);   // 8 threads

    const double* restrict xptr = x.data();
    std::complex<double>* restrict outptr = output.data();

    #pragma omp parallel for schedule(static, chunk)
    for (int k = 0; k < static_cast<int>(N); ++k)
    {
        std::complex<double> sum(0.0, 0.0);
        for (int n = 0; n < static_cast<int>(N); ++n)
        {
            double ang = two_pi_over_N * static_cast<double>(n) * static_cast<double>(k);
            double c = std::cos(ang);
            double s = -std::sin(ang);            // Euler's formula e^{-iθ}
            sum += std::complex<double>(xptr[n] * c, xptr[n] * s);
        }
        outptr[k] = sum;
    }
}
