 * --- Notes on the implementation -------------------------------------------------
 * 1) Loop is written with a raw pointer for maximum throughput and to allow
 *    the compiler to unroll / vectorise (if desired).
 * 2) OpenMP is used to divide the work across all available threads.  Because
 *    the number of bins is very small we perform a per‑thread temporary
 *    histogram and then combine them at the end, avoiding costly atomic
 *    updates.
 * 3) The function is `inline` to minimize call overhead when used from a
 *    tight loop in the benchmark harness.
 */
inline void binsBy10Count(const std::vector<double>& x,
                          std::array<std::size_t, 10>& bins)
{
    // initialise global bins to zero
    bins.fill(0);

    // If the input is empty just return (no work to do)
    if (x.empty()) return;

    // Determine the number of available threads
    const int nthreads = omp_get_max_threads();

    // Allocate thread‑local histograms
    std::vector<std::array<std::size_t, 10>> thread_bins(nthreads);
    for (auto& tb : thread_bins) tb.fill(0);

    // Parallel loop
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        std::array<std::size_t, 10> &local_bins = thread_bins[tid];

        // Use two‑phase chunking: each thread gets a contiguous block
        // of the input array.  This improves cache affinity.
        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < x.size(); ++i) {
            const size_t bin = static_cast<size_t>(x[i] / 10.0);
            // `bin` is guaranteed to be in [0,10] due to input contract
            local_bins[bin] += 1;
        }
    } // end of parallel region

    // Combine per‑thread histograms into the final result
    for (int t = 0; t < nthreads; ++t) {
        const auto& tb = thread_bins[t];
        for (size_t b = 0; b < 10; ++b) {
            bins[b] += tb[b];
        }
    }
}
