#pragma once
#include <vector>
#include <array>
#include <cstddef>
#include <limits>
#include <cstring>
#include <omp.h>

/// Count pixel intensities.
/// `image` may contain values 0‑255. The resulting histogram is stored in
/// `bins` (size 256). The function is thread‑safe and fully deterministic.
///
/// Internally, it uses a per‑thread local histogram to avoid atomic
/// contention and then atomically merges the local results into the global
/// histogram. The code keeps its behaviour identical to the original version
/// but is fully parallel and highly cache‑friendly on up‑to‑8 core machines.
void pixelCounts(std::vector<int> const& image, std::array<std::size_t, 256> &bins)
{
    constexpr std::size_t K = 256;
    // initialize global bins to zero
    std::memset(bins.data(), 0, K * sizeof(std::size_t));

    const std::size_t n = image.size();
    if (n == 0) return;

    // The number of threads is limited to 8 by the harness, but we can
    // adapt to any number of available processors.
    const int nthreads = std::min(8, omp_get_max_threads());

    // Allocate a temporary block of local histograms (one per thread)
    // Stored in a contiguous array to keep it cache friendly.
    std::vector<std::array<std::size_t, K>> local_hist(nthreads);
    for (int t = 0; t < nthreads; ++t) {
        std::memset(local_hist[t].data(), 0, K * sizeof(std::size_t));
    }

    // Parallel prefix processing: each thread works on a range.
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        std::array<std::size_t, K> &local = local_hist[tid];

        // Manual loop splitting: static schedule for balanced workload.
        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < n; ++i) {
            const int val = image[i];
            // VAL is guaranteed to be 0..255, no bounds check needed.
            ++local[val];
        }
    }

    // Merge local histograms into the global histogram.
    // This step is single‑threaded (or could be parallelized with atomic adds)
    // but the overhead is negligible compared to the parsing step.
    for (int t = 0; t < nthreads; ++t) {
        const std::array<std::size_t, K> &local = local_hist[t];
        for (std::size_t i = 0; i < K; ++i) {
            bins[i] += local[i];
        }
    }
}
