#pragma once
#include <vector>
#include <cstddef>

/* Count the number of connected components in the undirected graph defined by
   the adjacency matrix A stored in row‑major order.
   The implementation replaces the recursive DFS with an explicit stack and
   uses a plain byte vector for the visited flag to avoid the overhead of
   std::vector<bool>. */
int componentCount(std::vector<int> const& A, size_t N)
{
    // Use a byte array instead of std::vector<bool> for speed.
    std::vector<char> visited(N, 0);
    int count = 0;

    // Temporary stack for the iterative DFS.
    std::vector<int> stack;
    stack.reserve(N);

    for (size_t start = 0; start < N; ++start)
    {
        if (visited[start])
            continue;

        // New component found.
        ++count;

        // Begin a DFS from the start node.
        stack.push_back(static_cast<int>(start));
        visited[start] = 1;

        while (!stack.empty())
        {
            int v = stack.back();
            stack.pop_back();

            const int* row = A.data() + v * N;

            for (size_t j = 0; j < N; ++j)
            {
                if (row[j] && !visited[j])
                {
                    visited[j] = 1;
                    stack.push_back(static_cast<int>(j));
                }
            }
        }
    }

    return count;
}
