/*
 * Return the distance between the closest two elements in the vector `x`.
 * Example:
 *   input: [7, 3, 9, 12, 31, 1]
 *   output: 2
 */
inline double closestPair(const std::vector<double>& x) {
    const std::size_t n = x.size();
    if (n < 2) return 0.0;

    // Make a copy so that we can sort without altering the caller's data.
    std::vector<double> sorted{x.begin(), x.end()};
    std::sort(sorted.begin(), sorted.end());

    // Parallel reduction over adjacent pairs.
    double minDist = std::numeric_limits<double>::max();

#ifdef _OPENMP
    #pragma omp parallel for reduction(min:minDist)
    for (std::size_t i = 1; i < n; ++i) {
        const double d = sorted[i] - sorted[i - 1];
        if (d < minDist) {
            minDist = d;
        }
    }
#else
    for (std::size_t i = 1; i < n; ++i) {
        const double d = sorted[i] - sorted[i - 1];
        if (d < minDist) minDist = d;
    }
#endif

    return minDist;
}
