/* Return the distance between the two closest points in the vector `points`.
 * The algorithm runs in O(n²) time but is heavily optimized: we work with
 * squared distances to avoid calling `sqrt` in the inner loop and we use
 * OpenMP to split the outer loop across up to 8 hardware threads.
 *
 * Note: The harness guarantees that the input vector will have at least 2
 * points, but we keep a guard just in case.
 */
double closestPair(std::vector<Point> const& points) {
    const size_t n = points.size();
    if (n < 2) return 0.0;

    const double INF = std::numeric_limits<double>::max();
    double minDist2 = INF;          // we keep squared distances

    // Parallel outer loop: each thread evaluates a chunk of i-values.
    #pragma omp parallel for schedule(static) reduction(+:minDist2)
    for (size_t i = 0; i < n - 1; ++i) {
        const Point& pi = points[i];
        for (size_t j = i + 1; j < n; ++j) {
            const double dx = points[j].x - pi.x;
            const double dy = points[j].y - pi.y;
            const double d2   = dx * dx + dy * dy;      // squared distance
            if (d2 < minDist2) minDist2 = d2;
        }
    }

    return std::sqrt(minDist2);
}
