/* Set every cell's value to 1 if it has exactly one neighbor that's a 1. Otherwise set it to 0.
   The function is fully parallelized with OpenMP and uses pointer arithmetic for speed.
   Input and output are NxN grids stored in row-major order.
*/
inline void cellsXOR(std::vector<int> const& input, std::vector<int> &output, size_t N) {
    // Ensure output has correct size
    if (output.size() < N*N) output.resize(N*N);

    // Parallel outer loop – each iteration works on a distinct row
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const int *in_row_up   = (i > 0)   ? &input[(i-1)*N] : nullptr;
        const int *in_row_down = (i < N-1) ? &input[(i+1)*N] : nullptr;
        int *out_row = &output[i*N];

        for (size_t j = 0; j < N; ++j) {
            int count = 0;

            // Up
            if (in_row_up && in_row_up[j] == 1) ++count;
            // Down
            if (in_row_down && in_row_down[j] == 1) ++count;
            // Left
            if (j > 0 && input[i*N + j - 1] == 1) ++count;
            // Right
            if (j < N-1 && input[i*N + j + 1] == 1) ++count;

            out_row[j] = (count == 1) ? 1 : 0;
        }
    }
