#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstddef>
#include <omp.h>

/* Compute the fourier transform of x. Store real part of results in r and
   imaginary in i.
   The function assumes that the input size is a power of two and that
   r and i have been resized to that size.
*/
void fft(std::vector<std::complex<double>> const& x,
         std::vector<double> &r,
         std::vector<double> &i)
{
    const std::size_t N = x.size();
    std::vector<std::complex<double>> a(x);           // in-place copy

    /* ---------- bit‑reversal permutation ---------- */
    std::size_t j = 0;
    for (std::size_t i1 = 0; i1 < N; ++i1)
    {
        if (i1 < j)
            std::swap(a[i1], a[j]);

        std::size_t m = N >> 1;
        while (j >= m && m != 0)
        {
            j -= m;
            m >>= 1;
        }
        j += m;
    }

    /* ---------- iterative radix‑2 Cooley‑Tukey ---------- */
    for (std::size_t step = 2; step <= N; step <<= 1)
    {
        const std::size_t half = step >> 1;
        const double angle = -2.0 * M_PI / static_cast<double>(step);
        const std::complex<double> w_unit(std::cos(angle), std::sin(angle));

        /* parallelise the outer butterfly loop */
        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += step)
        {
            std::complex<double> w(1.0, 0.0);
            for (std::size_t j1 = 0; j1 < half; ++j1)
            {
                const std::size_t index1 = k + j1;
                const std::size_t index2 = index1 + half;

                std::complex<double> t = w * a[index2];
                std::complex<double> u = a[index1];

                a[index1] = u + t;
                a[index2] = u - t;

                w *= w_unit;
            }
        }
    }

    /* ---------- split into real/imag parts ---------- */
    for (std::size_t k = 0; k < N; ++k)
    {
        r[k] = a[k].real();
        i[k] = a[k].imag();
    }
}
