// game_of_life_optimized.hpp
#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

inline void gameOfLife(std::vector<int> const& input, std::vector<int> &output, size_t N) {
    // Assume output is already sized N*N.  Parallelise over rows.
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        size_t base = i * N;
        size_t prev = (i > 0) ? (i-1) * N : SIZE_MAX;   // sentinel for bounds
        size_t next = (i+1 < N) ? (i+1) * N : SIZE_MAX;

        for (size_t j = 0; j < N; ++j) {
            int sum = 0;
            // vertical neighbours
            if (prev != SIZE_MAX) sum += input[prev + j];
            if (next != SIZE_MAX) sum += input[next + j];
            // horizontal neighbours
            if (j > 0)        sum += input[base + j - 1];
            if (j + 1 < N)    sum += input[base + j + 1];
            // diagonal neighbours
            if (prev != SIZE_MAX) {
                if (j > 0)        sum += input[prev + j - 1];
                if (j + 1 < N)    sum += input[prev + j + 1];
            }
            if (next != SIZE_MAX) {
                if (j > 0)        sum += input[next + j - 1];
                if (j + 1 < N)    sum += input[next + j + 1];
            }

            int cur = input[base + j];
            // Game of Life rules – keep integers 0/1
            output[base + j] = (cur == 1) ?
                                  ((sum == 2 || sum == 3) ? 1 : 0) :
                                  ((sum == 3) ? 1 : 0);
        }
    }
}
