struct Point {
    double x, y;
};

/* Monotone-chain convex hull (O(n log n))  
   Retains exact geometric behavior of the original implementation. */
inline static double cross(const Point& a, const Point& b, const Point& c) noexcept {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

void convexHull(const std::vector<Point>& points, std::vector<Point>& hull) {
    const std::size_t n = points.size();
    if (n < 3) { hull.assign(points.begin(), points.end()); return; }

    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) noexcept {
                  return (a.x < b.x) || (a.x == b.x && a.y < b.y);
              });

    // Allocate enough space for upper + lower hulls
    std::vector<Point> tmp(2 * n);
    std::size_t k = 0;

    // Build lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(tmp[k-2], tmp[k-1], sorted[i]) <= 0.0) --k;
        tmp[k++] = sorted[i];
    }

    // Build upper hull
    for (std::size_t i = n-1; i > 0; --i) {
        while (k >= 2 && cross(tmp[k-2], tmp[k-1], sorted[i-1]) <= 0.0) --k;
        tmp[k++] = sorted[i-1];
    }

    // Remove duplicate last point
    tmp.resize(k-1);
    hull.swap(tmp);      // avoid copy
}
