#pragma once
#include <vector>
#include <algorithm>
#include <limits>
#include <omp.h>

/*
 * Replace the i‑th element of the vector x with the minimum value from indices
 * 0 through i.
 *
 * Behaviour is identical to the original std::inclusive_scan implementation,
 * but this version is tuned for speed on a modern 8‑core x86‑64 machine
 * using GCC - O2 and OpenMP.
 */
void partialMinimums(std::vector<float> &x) {
    const std::size_t n = x.size();
    if (n == 0) return;

    const int nthreads = omp_get_max_threads();
    std::vector<float> blockMin(nthreads, std::numeric_limits<float>::max());

    // 1. Compute the minimum for each block (per thread)
    #pragma omp parallel num_threads(nthreads)
    {
        const int tid = omp_get_thread_num();
        const std::size_t per = (n + nthreads - 1) / nthreads; // block size
        const std::size_t start = tid * per;
        const std::size_t end   = std::min(start + per, n);

        if (start >= end) return; // some threads may be idle

        float localMin = std::numeric_limits<float>::max();
        for (std::size_t i = start; i < end; ++i)
            localMin = std::min(localMin, x[i]);

        blockMin[tid] = localMin;
    }

    // 2. Prefix–sum of block minima to know the minimum before each block
    std::vector<float> blockPrefix(nthreads, std::numeric_limits<float>::max());
    float acc = std::numeric_limits<float>::max();
    for (int i = 0; i < nthreads; ++i) {
        blockPrefix[i] = acc;          // min of all previous blocks
        acc = std::min(acc, blockMin[i]); // min up to this block
    }

    // 3. Scan each block with the knowledge of the previous global minimum
    #pragma omp parallel num_threads(nthreads)
    {
        const int tid = omp_get_thread_num();
        const std::size_t per = (n + nthreads - 1) / nthreads;
        const std::size_t start = tid * per;
        const std::size_t end   = std::min(start + per, n);

        if (start >= end) return;

        float runningMin = blockPrefix[tid];
        for (std::size_t i = start; i < end; ++i) {
            runningMin = std::min(runningMin, x[i]);
            x[i] = runningMin;
        }
    }
}
