struct Result {
    int startTime, duration;
    float value;
};

// Parallel quick‑sort implementation using OpenMP tasks.
// The recursion depth is limited to avoid too fine‑grained tasks.
static inline void parallel_quicksort(std::vector<Result>::iterator first,
                                      std::vector<Result>::iterator last,
                                      const std::ptrdiff_t max_depth = 3) {
    if (first >= last || std::distance(first, last) <= 1) return;

    // Use the element near the middle as pivot (median-of-three).
    auto mid = first + std::distance(first, last) / 2;
    Result pivot = (*mid < *first) ? *first :
                   (*mid < *last) ? *mid : *last;
    auto it = std::partition(first, last, [&](const Result& r) {
        return r.startTime < pivot.startTime;
    });

    // Recurse on the two halves.
    if (max_depth > 0) {
#pragma omp task
        parallel_quicksort(first, it, max_depth - 1);
#pragma omp task
        parallel_quicksort(it, last, max_depth - 1);
#pragma omp taskwait
    } else {
        parallel_quicksort(first, it, 0);
        parallel_quicksort(it, last, 0);
    }
}

inline void sortByStartTime(std::vector<Result> &results) {
    if (results.size() < 2) return;
#pragma omp parallel
    {
#pragma omp single nowait
        parallel_quicksort(results.begin(), results.end());
    }
}
