#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*     
 * Multi-threaded, cache‑friendly GEMM
 * A: M × K matrix (row‑major)
 * B: K × N matrix (row‑major)
 * C: M × N matrix   (row‑major)
 *
 * C += A × B
 */
inline void gemm(const std::vector<double>& A,
                 const std::vector<double>& B,
                 std::vector<double>&        C,
                 std::size_t M, std::size_t K, std::size_t N)
{
    constexpr std::size_t BLOCK_M = 64;   // block size for rows of A / C
    constexpr std::size_t BLOCK_K = 64;   // block size for columns of A / rows of B
    constexpr std::size_t BLOCK_N = 64;   // block size for columns of B / C

    const double* a = A.data();
    const double* b = B.data();
          double* c = C.data();

    #pragma omp parallel for schedule(static)
    for (std::size_t ii = 0; ii < M; ii += BLOCK_M) {
        std::size_t imax = std::min(ii + BLOCK_M, M);
        for (std::size_t kk = 0; kk < K; kk += BLOCK_K) {
            std::size_t kmax = std::min(kk + BLOCK_K, K);
            for (std::size_t jj = 0; jj < N; jj += BLOCK_N) {
                std::size_t jmax = std::min(jj + BLOCK_N, N);

                for (std::size_t i = ii; i < imax; ++i) {
                    const std::size_t iN = i * N;
                    const std::size_t iK = i * K;
                    double*   c_ptr = c + iN;
                    const double* a_ptr = a + iK;
                    for (std::size_t k = kk; k < kmax; ++k) {
                        double aik = a_ptr[k];
                        const double* b_row = b + k * N;
                        for (std::size_t j = jj; j < jmax; ++j) {
                            c_ptr[j] += aik * b_row[j];
                        }
                    }
                }
            }
        }
    }
}
