/*-------------------------------------*
 *  Point definition                   *
 *-------------------------------------*/
struct Point
{
    double x, y;
};

/*-------------------------------------*
 *  Distance helper (inline)           *
 *-------------------------------------*/
inline double dist(const Point& a, const Point& b) noexcept
{
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::hypot(dx, dy);          // faster than sqrt(dx*dx+dy*dy)
}

/*-------------------------------------*
 *  Cross product (inline)             *
 *-------------------------------------*/
inline double cross(const Point& a, const Point& b, const Point& c) noexcept
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

/*-------------------------------------*
 *  Convex hull perimeter               *
 *-------------------------------------*/
inline double convexHullPerimeter(const std::vector<Point>& points) noexcept
{
    const size_t n = points.size();
    if (n < 3) return 0.0;

    // Make a local copy so we can sort
    std::vector<Point> pt(points);

    // 1. Sort points by x, then y
    std::sort(pt.begin(), pt.end(),
              [](const Point& a, const Point& b) noexcept
              {
                  return (a.x < b.x) || (a.x == b.x && a.y < b.y);
              });

    // 2. Build upper + lower hull in one array
    std::vector<Point> hull(2 * n);     // maximum possible size
    size_t k = 0;                       // number of points in hull

    // lower hull
    for (size_t i = 0; i < n; ++i)
    {
        while (k >= 2 && cross(hull[k-2], hull[k-1], pt[i]) <= 0.0)
            --k;
        hull[k++] = pt[i];
    }

    // upper hull
    for (size_t i = n-1, t = k+1; i > 0; --i)
    {
        while (k >= t && cross(hull[k-2], hull[k-1], pt[i-1]) <= 0.0)
            --k;
        hull[k++] = pt[i-1];
    }

    hull.resize(k-1);   // last point == first point

    // 3. Compute perimeter
    double perim = 0.0;
    for (size_t i = 0; i + 1 < hull.size(); ++i)
        perim += dist(hull[i], hull[i+1]);
    perim += dist(hull.front(), hull.back());

    return perim;
}
