#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
   Optimised matrix‑vector multiplication (GEMV).

   Parameters:
   - A:  M x N matrix stored in row‑major order
   - x:  vector of length N
   - y:  output vector of length M (must be pre‑allocated)
   - M, N: matrix dimensions

   The function preserves the original semantics: y[i] = Σ_j A[i*N + j] * x[j]
   but performs the computation in parallel with a simple cache‑friendly
   tiling strategy to improve memory access patterns.
*/

constexpr std::size_t TILE_ROWS = 64;   // tuned for typical cache sizes

inline void gemv(std::vector<double> const& A,
                 std::vector<double> const& x,
                 std::vector<double> & y,
                 std::size_t M, std::size_t N)
{
    // Ensure output vector is the correct size
    y.assign(M, 0.0);

    // Parallel outer loop over row tiles
    #pragma omp parallel for schedule(static)
    for (std::size_t tile = 0; tile < M; tile += TILE_ROWS) {
        std::size_t row_end = std::min(tile + TILE_ROWS, M);
        for (std::size_t i = tile; i < row_end; ++i) {
            double sum = 0.0;
            const double* a_row = &A[i * N];
            const double* x_ptr = x.data();
            // Inner loop: unroll by 4 for better instruction-level parallelism
            std::size_t j = 0;
            for (; j + 3 < N; j += 4) {
                sum += a_row[j]   * x_ptr[j];
                sum += a_row[j+1] * x_ptr[j+1];
                sum += a_row[j+2] * x_ptr[j+2];
                sum += a_row[j+3] * x_ptr[j+3];
            }
            for (; j < N; ++j) {
                sum += a_row[j] * x_ptr[j];
            }
            y[i] = sum;
        }
    }
}
