```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * LU factorization of the matrix A into A = LU.
 * The result is stored in-place in row-major format.
 *
 * Parameters
 * ----------
 * A : double[]
 *     NxN matrix in row-major order.  Modified to contain L (strictly
 *     lower triangular with unit diagonal) in the sub‑diagonal part
 *     and U (strictly upper triangular including the diagonal) in the
 *     upper triangular part.
 * N : size_t
 *     Dimension of the matrix (N ≥ 1).
 */
inline void luFactorize(std::vector<double> &A, size_t N)
{
    const size_t stride = N;                     // row stride
    double *const a = A.data();                  // Raw pointer for speed

    for (size_t k = 0; k < N; ++k) {
        const double aik = a[k * stride + k];    // pivot

        // No division by zero guard – the harness guarantees non‑singular matrices.
        double inv_aik = 1.0 / aik;

#pragma omp parallel for schedule(static)
        for (size_t i = k + 1; i < N; ++i) {
            const size_t row_i = i * stride;
            const size_t row_k = k * stride;

            // Compute the multiplier and store it in the lower part
            double factor = a[row_i + k] * inv_aik;
            a[row_i + k] = factor;

            // Update the remaining part of the row
            for (size_t j = k + 1; j < N; ++j) {
                a[row_i + j] -= factor * a[row_k + j];
            }
        }
    }
}
