#pragma once
#include <vector>

void solveLinearSystem(const std::vector<double>& A, const std::vector<double>& b,
                       std::vector<double>& x, size_t N) {
    // Work on copies to preserve the original inputs
    std::vector<double> A_copy = A;
    std::vector<double> b_copy = b;

    // -------------------------------------------------
    // Gaussian elimination (forward elimination)
    // -------------------------------------------------
    for (size_t i = 0; i + 1 < N; ++i) {
        const double* Ai = &A_copy[i * N];
        const double* Aidiag = &Ai[i];
        const double pivot = *Aidiag;
        if (pivot == 0.0) return;                     // singular matrix

        for (size_t j = i + 1; j < N; ++j) {
            double* Aj = &A_copy[j * N];
            const double factor = Aj[i] / pivot;       // factor = A[j][i] / pivot
            Aj[i] = 0.0;                               // explicit zeroing
            for (size_t k = i + 1; k < N; ++k) {
                Aj[k] -= factor * Ai[k];
            }
            b_copy[j] -= factor * b_copy[i];
        }
    }

    // -------------------------------------------------
    // Back substitution
    // -------------------------------------------------
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        const double* Ai = &A_copy[i * N];
        for (size_t j = i + 1; j < N; ++j) {
            sum += Ai[j] * x[j];
        }
        x[i] = (b_copy[i] - sum) / Ai[i];
    }
}
