#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   Example:
   input: A=[{0,0,1}, {0,1,1}, {1,1,-2}] b=[1,4]
   output: x=[3,-2]
*/
void solveLinearSystem(std::vector<COOElement> const& A,
                       std::vector<double> const& b,
                       std::vector<double>& x,
                       size_t N)
{
    // Allocate continuous dense matrix
    std::vector<double> mat(N * N, 0.0);

    // Fill the matrix from the COO representation
    for (auto const& e : A) {
        mat[e.row * N + e.column] = e.value;
    }

    // Make a copy of b
    std::vector<double> b_copy = b;
    x.assign(N, 0.0);

    // Gaussian elimination with partial pivoting
    for (size_t i = 0; i < N; ++i) {
        // Find pivot in column i
        size_t maxRow = i;
        double maxVal = std::fabs(mat[i * N + i]);
        for (size_t k = i + 1; k < N; ++k) {
            double val = std::fabs(mat[k * N + i]);
            if (val > maxVal) {
                maxVal = val;
                maxRow = k;
            }
        }

        // Swap rows i and maxRow if needed
        if (maxRow != i) {
            for (size_t j = i; j < N; ++j) {
                std::swap(mat[maxRow * N + j], mat[i * N + j]);
            }
            std::swap(b_copy[maxRow], b_copy[i]);
        }

        double pivot = mat[i * N + i];
        // Eliminate rows below i
#pragma omp parallel for schedule(static)
        for (size_t k = i + 1; k < N; ++k) {
            double factor = -mat[k * N + i] / pivot;
            for (size_t j = i; j < N; ++j) {
                if (j == i) {
                    mat[k * N + j] = 0.0;
                } else {
                    mat[k * N + j] += factor * mat[i * N + j];
                }
            }
            b_copy[k] += factor * b_copy[i];
        }
    }

    // Back substitution
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        x[i] = b_copy[i] / mat[i * N + i];
        for (int k = i - 1; k >= 0; --k) {
            b_copy[k] -= mat[k * N + i] * x[i];
        }
    }
}
