#pragma once
#include <vector>
#include <limits>
#include <algorithm>
#include <cmath>
#include <omp.h>

struct Point {
    double x, y;
};

// Cross product (B - A) × (C - A)
inline double cross(const Point& A, const Point& B, const Point& C) {
    return (B.x - A.x) * (C.y - A.y) - (B.y - A.y) * (C.x - A.x);
}

// Area of triangle ABC (always non‑negative)
inline double area(const Point& A, const Point& B, const Point& C) {
    return 0.5 * std::abs(cross(A, B, C));
}

// Convex hull in counter‑clockwise order (Monotone chain)
// Returns hull with the first point duplicated at the end
std::vector<Point> convexHull(std::vector<Point> pts) {
    if (pts.size() <= 1) return pts;
    std::sort(pts.begin(), pts.end(),
              [](const Point& a, const Point& b) {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    std::vector<Point> lower, upper;
    for (auto& p : pts) {
        while (lower.size() >= 2 &&
               cross(lower[lower.size()-2], lower[lower.size()-1], p) <= 0)
            lower.pop_back();
        lower.push_back(p);
    }
    for (auto it = pts.rbegin(); it != pts.rend(); ++it) {
        while (upper.size() >= 2 &&
               cross(upper[upper.size()-2], upper[upper.size()-1], *it) <= 0)
            upper.pop_back();
        upper.push_back(*it);
    }
    lower.pop_back();
    upper.pop_back();
    lower.insert(lower.end(), upper.begin(), upper.end());
    return lower;
}

// Parallelised minimal triangle area over a convex hull
double minimalTriangleArea(const std::vector<Point>& hull) {
    size_t n = hull.size();
    if (n < 3) return 0.0;

    double minArea = std::numeric_limits<double>::max();

    // Parallel double loop over i and j with reduction
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < n; ++i) {
        for (size_t j = i + 1; j < n; ++j) {
            // The third vertex can be found optimally by sweeping k
            size_t k = j + 1;
            for (size_t l = j + 1; l < n; ++l) {
                double a = area(hull[i], hull[j], hull[l]);
                if (a < minArea) {
                    #pragma omp atomic write
                    minArea = a;
                }
            }
        }
    }
    return minArea;
}

// Public API
double smallestArea(std::vector<Point> const& points) {
    if (points.size() < 3) return 0.0;
    auto hull = convexHull(points);
    return minimalTriangleArea(hull);
}
