static constexpr int constexpr edgeKernel[3][3] = {
    { -1, -1, -1 },
    { -1,  8, -1 },
    { -1, -1, -1 }
};

/**
 * Convolve a NxN grayscale image with the 3x3 edge kernel.
 *
 * @param imageIn  Input image, row‑major, N*N elements.
 * @param imageOut Output image, row‑major, N*N elements.
 * @param N        Dimension of the square image.
 *
 * The implementation uses OpenMP parallelisation, pointer arithmetic,
 * and a hand‑rolled loop unroll for the 3×3 kernel.  All behaviour
 * (including out‑of‑bounds clamping to 0 and 255) matches the original
 * reference implementation.
 */
inline void convolveKernel(std::vector<int> const& imageIn,
                           std::vector<int> &imageOut,
                           const size_t N)
{
    // Ensure vector sizes are correct
    if (imageIn.size() < N * N) return;
    if (imageOut.size() < N * N) return;

    const int*  in  = imageIn.data();
    int*        out = imageOut.data();

    /* Parallelise over all pixels.  OpenMP will split the outer
       i‑loop among available threads.  The inner j‑loop is
       executed sequentially per thread to keep stack usage low. */
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const size_t rowBase = i * N;
        for (size_t j = 0; j < N; ++j) {
            /* Compute convolution using the fixed 3×3 kernel.
               The edge pixels are handled by boundary checks. */
            int sum = 0;

            // Top row
            if (i > 0) {
                const size_t top = (i - 1) * N;
                sum += in[top + j - 1]   * edgeKernel[0][0];
                sum += in[top + j]       * edgeKernel[0][1];
                sum += in[top + j + 1]   * edgeKernel[0][2];
            }

            // Middle row
            sum += in[rowBase + j - 1] * edgeKernel[1][0];
            sum += in[rowBase + j]     * edgeKernel[1][1];
            sum += in[rowBase + j + 1] * edgeKernel[1][2];

            // Bottom row
            if (i + 1 < N) {
                const size_t bottom = (i + 1) * N;
                sum += in[bottom + j - 1] * edgeKernel[2][0];
                sum += in[bottom + j]     * edgeKernel[2][1];
                sum += in[bottom + j + 1] * edgeKernel[2][2];
            }

            /* Clamp to 0‑255 using a small branchless trick. */
            sum = std::min(std::max(sum, 0), 255);
            out[rowBase + j] = sum;
        }
    }
}
