#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

/*--------------------------------------------------------------------
   Iterative radix‑2 Cooley‑Tukey FFT.
   Input and output vectors are of size N = 2^p (p <= 30).
   The function preserves the original semantics: it writes the DFT
   of `x` into `output` (bit‑reversal already applied inside).
--------------------------------------------------------------------*/
static inline void fft_radix2(const std::vector<std::complex<double>>& x,
                              std::vector<std::complex<double>>& output)
{
    const size_t N = x.size();
    if (N == 0) return;

    // Prepare output buffer
    output.assign(x.begin(), x.end());

    /*-------------------------- Bit‑reverse -----------------------*/
    // Compute the bit‑reversed index for every position once
    // (works for up to 2^32 elements, but N is < 2^30 in practice).
    const unsigned int bits = static_cast<unsigned int>(std::log2(N));
    std::vector<size_t> rev(N);
    for (size_t i = 0; i < N; ++i)
    {
        unsigned int r = static_cast<unsigned int>(i);
        r = ((r & 0xaaaaaaaa) >> 1) | ((r & 0x55555555) << 1);
        r = ((r & 0xcccccccc) >> 2) | ((r & 0x33333333) << 2);
        r = ((r & 0xf0f0f0f0) >> 4) | ((r & 0x0f0f0f0f) << 4);
        r = ((r & 0xff00ff00) >> 8) | ((r & 0x00ff00ff) << 8);
        r = ((r >> 16) | (r << 16));
        rev[i] = r >> (32 - bits);
    }

    // Swapping stage (in place); parallelized because each swap is
    // independent once the bit‑reversed indices are known.
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        size_t j = rev[i];
        if (j > i)
            std::swap(output[i], output[j]);
    }

    /*-------------------------- FFT butterflies -----------------*/
    // Pre‑compute the twiddle factor for a full cycle (half‑sine).
    const double pi2 = 2.0 * M_PI;
    // Main loop: levels from 1 to log2(N)
    for (size_t level = 1; level <= bits; ++level)
    {
        const size_t m = 1ULL << level;          // size of sub‑transform
        const size_t half_m = m >> 1;
        const double angle = -pi2 / static_cast<double>(m);
        const std::complex<double> w_m(std::cos(angle), std::sin(angle));

        // For each block of size m, process all butterflies
        #pragma omp parallel for schedule(static)
        for (size_t k = 0; k < N; k += m)
        {
            std::complex<double> w(1.0, 0.0);
            for (size_t j = 0; j < half_m; ++j)
            {
                const size_t idx1 = k + j;
                const size_t idx2 = idx1 + half_m;
                const std::complex<double> t = w * output[idx2];
                output[idx2] = output[idx1] - t;
                output[idx1] += t;
                w *= w_m;
            }
        }
    }
}

/*--------------------------------------------------------------------
   Public interface matching the original harness.
--------------------------------------------------------------------*/
inline void fft(const std::vector<std::complex<double>>& x,
                std::vector<std::complex<double>>& output)
{
    fft_radix2(x, output);
}
