#pragma once
#include <algorithm>
#include <execution>
#include <numeric>
#include <vector>

struct ArgSortElem
{
    float value;
    std::size_t index;
};

inline void ranks(std::vector<float> const& x, std::vector<std::size_t>& ranks_)
{
    const std::size_t n = x.size();
    // Ensure output vector has correct size
    if (ranks_.size() != n) ranks_.resize(n);

    // Build an array of value/index pairs
    std::vector<ArgSortElem> elems;
    elems.reserve(n);
    for (std::size_t i = 0; i < n; ++i)
        elems.push_back({x[i], i});

    // Parallel sort by value, then by index to break ties deterministically
    std::sort(std::execution::par, elems.begin(), elems.end(),
              [](const ArgSortElem& a, const ArgSortElem& b) noexcept {
                  if (a.value != b.value) return a.value < b.value;
                  return a.index < b.index;
              });

    // Fill the ranks array
    for (std::size_t i = 0; i < n; ++i)
        ranks_[elems[i].index] = i;
}
