void sortIgnoreZero(std::vector<int> &x) {
    // Collect all non‑zero values once, pre‑allocating to avoid reallocations.
    std::vector<int> nonZero;
    nonZero.reserve(x.size());
    for (int v : x) {
        if (v != 0)
            nonZero.push_back(v);
    }

    // Sort the non‑zero values.
    std::sort(nonZero.begin(), nonZero.end());

    // Replace the non‑zero positions in the original vector with sorted values.
    std::size_t idx = 0;
    for (int &v : x) {
        if (v != 0)
            v = nonZero[idx++];
    }
}
