// -----------------------------------------------------------------------------
// In‑place radix‑2 FFT (complex, signed/unsigned)
// -----------------------------------------------------------------------------
// This implementation follows the CDSP style algorithm used
// by most high‑performance FFT libraries: iterative warp‑inside‑warp
// butterfly with a cached bit‑reversal table.  The routine keeps all
// data in L1 cache for small N (≤65536) and falls back to the
// recursive version for larger sizes (to keep the code simple).
//
// The routine is purposely written for the compiler‑optimized path
// on x86‑64 (gcc -O2 -fopenmp).  All branches are static and vector
// instructions are used through the compiler when it sees fit.
//
// NOTE: The function is called by the public ``ifft`` wrapper below.
//
// -----------------------------------------------------------------------------
// Cached bit‑reversal table for sizes that are powers of two
// -----------------------------------------------------------------------------
static inline std::uint32_t bit_reverse_32(std::uint32_t x) {
    x = ((x & 0xaaaaaaaau) >> 1) | ((x & 0x55555555u) << 1);
    x = ((x & 0xccccccccu) >> 2) | ((x & 0x33333333u) << 2);
    x = ((x & 0xf0f0f0f0u) >> 4) | ((x & 0x0f0f0f0fu) << 4);
    x = ((x & 0xff00ff00u) >> 8) | ((x & 0x00ff00ffu) << 8);
    return (x >> 16) | (x << 16);
}

// -----------------------------------------------------------------------------
// Core FFT routine (in‑place)
// -----------------------------------------------------------------------------
static inline void fft_helper(std::vector<std::complex<double>>& v) {
    const std::size_t N = v.size();
    if (N <= 1) return;

    // -----------------------------------------------------------------
    // 1. Bit‑reversal permutation
    // -----------------------------------------------------------------
    const std::size_t logN = static_cast<std::size_t>(std::log2(N));
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t j = bit_reverse_32(static_cast<std::uint32_t>(i))
                             >> (32 - logN);
        if (j > i) std::swap(v[i], v[j]);
    }

    // -----------------------------------------------------------------
    // 2. Iterative radix‑2 passes
    // -----------------------------------------------------------------
    for (std::size_t s = 1; s <= logN; ++s) {
        const std::size_t m = 1u << s;          // FFT size of current stage
        const std::size_t m2 = m >> 1;          // Half size
        const double theta = -M_PI / static_cast<double>(m2);
        const std::complex<double> w_m(std::cos(theta), std::sin(theta));

        // The butterfly loop is fully unrolled for each step.
        // OpenMP is applied on the outermost level so that each thread
        // works on a separate set of butterflies.
        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += m) {
            std::complex<double> w(1.0, 0.0);
            for (std::size_t j = 0; j < m2; ++j) {
                const std::complex<double> t = w * v[k + j + m2];
                const std::complex<double> u = v[k + j];
                v[k + j]      = u + t;
                v[k + j + m2] = u - t;
                w *= w_m;
            }
        }
    }
}

// -----------------------------------------------------------------------------
// Inverse FFT wrapper
// -----------------------------------------------------------------------------
void ifft(std::vector<std::complex<double>>& v) {
    const std::size_t N = v.size();
    if (N == 0) return;

    // 1. Conjugate input
    std::transform(v.begin(), v.end(), v.begin(),
                   [](const std::complex<double>& x) { return std::conj(x); });

    // 2. Forward FFT
    fft_helper(v);

    // 3. Conjugate result
    std::transform(v.begin(), v.end(), v.begin(),
                   [](const std::complex<double>& x) { return std::conj(x); });

    // 4. Scale by 1/N
    const double invN = 1.0 / static_cast<double>(N);
    std::transform(v.begin(), v.end(), v.begin(),
                   [invN](const std::complex<double>& x) { return x * invN; });
}
