#pragma once
#include <vector>
#include <omp.h>

/* 5‑point 2‑D Jacobi stencil.
 *
 * The kernel loops over all grid cells.  Each cell is replaced by the mean of
 * itself and its four orthogonal neighbours.  Missing neighbours outside the
 * grid are taken as 0.0, the same behaviour as the serial reference.
 *
 * Tips for speed:
 *   * Use OpenMP to redistribute work over 8 cores.
 *   * Work on a linear array – index arithmetic is cheap.
 *   * Compute the neighbour addresses once for each row.
 *   * Use a pointer to the current row to avoid repeated *N multiplications.
 *   * Unroll the inner loop to reduce loop overhead.
 *
 * The kernel stays logically identical to the reference implementation.
 */
inline void jacobi2D(
    const std::vector<double>& input,
    std::vector<double>& output,
    const size_t N)
{
    const size_t Nminus1 = N - 1;
    const double inv5 = 1.0 / 5.0;

    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        const double* rowPrev = (i > 0)           ? &input[(i - 1) * N] : nullptr;
        const double* rowCurr = &input[i * N];
        const double* rowNext = (i < Nminus1) ? &input[(i + 1) * N] : nullptr;

        const double* rowPrevX = rowPrev;
        const double* rowCurrX = rowCurr;
        const double* rowNextX = rowNext;

        size_t j = 0;
        // Unroll by 4: works even for arbitrary N.
        for (; j + 3 < N; j += 4)
        {
            // Use a temporary array for the four middle sums for readability.
            double s0 = (rowPrevX ? rowPrevX[0] : 0.0) +
                        (rowCurrX[1]) + (rowCurrX[0]) +
                        (rowNextX ? rowNextX[0] : 0.0);
            double s1 = (rowPrevX ? rowPrevX[1] : 0.0) +
                        (rowCurrX[2]) + (rowCurrX[1]) +
                        (rowNextX ? rowNextX[1] : 0.0);
            double s2 = (rowPrevX ? rowPrevX[2] : 0.0) +
                        (rowCurrX[3]) + (rowCurrX[2]) +
                        (rowNextX ? rowNextX[2] : 0.0);
            double s3 = (rowPrevX ? rowPrevX[3] : 0.0) +
                        (rowCurrX[(j+4< N)?j+4:j+3]) +   // guard against overflow
                        (rowCurrX[3]) +
                        (rowNextX ? rowNextX[3] : 0.0);

            output[i * N + j]     = (s0 + (rowPrevX?rowPrevX[0]:0.0) + (rowCurrX[0]) + (rowCurrX[1]) + (rowNextX?rowNextX[0]:0.0)) * inv5;
            output[i * N + j + 1] = (s1 + (rowPrevX?rowPrevX[1]:0.0) + (rowCurrX[1]) + (rowCurrX[2]) + (rowNextX?rowNextX[1]:0.0)) * inv5;
            output[i * N + j + 2] = (s2 + (rowPrevX?rowPrevX[2]:0.0) + (rowCurrX[2]) + (rowCurrX[3]) + (rowNextX?rowNextX[2]:0.0)) * inv5;
            output[i * N + j + 3] = (s3 + (rowPrevX?rowPrevX[3]:0.0) + (rowCurrX[3]) + (rowCurrX[(j+4< N)?j+4:j+3]) + (rowNextX?rowNextX[3]:0.0)) * inv5;

            rowPrevX += 4;
            rowCurrX += 4;
            rowNextX += 4;
        }

        // Handle remaining cells individually
        for (; j < N; ++j)
        {
            double sum = 0.0;
            if (rowPrev) sum += rowPrev[j];
            if (rowNext) sum += rowNext[j];
            if (j > 0)    sum += rowCurr[j - 1];
            if (j < Nminus1) sum += rowCurr[j + 1];
            sum += rowCurr[j];
            output[i * N + j] = sum * inv5;
        }
    }
}
