#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <algorithm>
#include <omp.h>

// ---------------------------------------------------------------------------
//  This implementation implements an in‑place radix‑2 Cooley–Tukey FFT.
//  It follows the structure of the original routine but replaces the
//  manual power‑swapping loops with a conventional iterative butterfly
//  algorithm.  All stages are processed sequentially – this is the
//  usual requirement of the Cooley–Tukey algorithm – but the inner
//  loop that operates on independent butterfly groups is parallelised
//  with OpenMP.  The bit‑reversal is performed with a lookup table
//  that contains the reversed indices for the first 512 elements; the
//  remaining bits are shuffled using a small helper function.  Finally
//  the conjugation step is vectorised.
//
//  The function signature is kept identical to the original:
//      void fftConjugate(std::vector<std::complex<double>>& x)
// ---------------------------------------------------------------------------

namespace fft_private
{
    // ---------------------------------------------------------------
    // Compile‑time push to the vector table for 512 elements
    // ---------------------------------------------------------------
    constexpr std::size_t BITREV_TABLE_SIZE = 512;
    inline static std::array<std::uint32_t, BITREV_TABLE_SIZE> build_bitrev()
    {
        std::array<std::uint32_t, BITREV_TABLE_SIZE> tbl{};
        for (std::uint32_t i = 0; i < BITREV_TABLE_SIZE; ++i)
        {
            std::uint32_t rev = 0;
            std::uint32_t x   = i;
            for (int b = 0; b < 9; ++b)
            {
                rev = (rev << 1) | (x & 1);
                x >>= 1;
            }
            tbl[i] = rev;
        }
        return tbl;
    }
    static const std::array<std::uint32_t, BITREV_TABLE_SIZE> bitrev_table = build_bitrev();
}

// ---------------------------------------------------------------------------
//  Main transform function
// ---------------------------------------------------------------------------
inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N <= 1) return;

    // ---- Pre‑compute twiddle factors for all stages ----
    const std::size_t logN = static_cast<std::size_t>(std::log2(static_cast<double>(N)));
    std::vector<std::complex<double>> twiddles(N / 2);
    const double two_pi = 2.0 * M_PI;
    for (std::size_t k = 0; k < N / 2; ++k)
        twiddles[k] = std::exp(std::complex<double>(0, -two_pi * k / static_cast<double>(N)));

    // ---- Butterfly stages ----
    for (std::size_t stage = 1; stage <= logN; ++stage)
    {
        const std::size_t span   = 1U << stage;          // 2 * butterfly size
        const std::size_t half   = span >> 1;            // butterfly size
        const std::size_t istride = N / span;            // step for twiddle index
        const std::size_t step   = span;                 // stride for outer index

        // Parallelise over independent sets of butterflies
        #pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += span)
        {
            for (std::size_t j = 0; j < half; ++j)
            {
                const std::size_t idx1 = i + j;
                const std::size_t idx2 = i + j + half;
                const std::size_t t_idx = j * istride;
                std::complex<double> t = twiddles[t_idx] * x[idx2];
                x[idx2] = x[idx1] - t;
                x[idx1] += t;
            }
        }
    }

    // ---- Bit‑reversal permutation ----
    std::size_t m = 0;
    for (std::size_t tmp = N; tmp > 1; tmp >>= 1) ++m;

    const std::size_t shift = 32 - m;
    for (std::size_t i = 0; i < N; ++i)
    {
        std::uint32_t rev = fft_private::bitrev_table[i & 0x1FF] << shift;
        rev = ((rev & 0xaaaaaaaa) >> 1) | ((rev & 0x55555555) << 1);
        rev = ((rev & 0xcccccccc) >> 2) | ((rev & 0x33333333) << 2);
        rev = ((rev & 0xf0f0f0f0) >> 4) | ((rev & 0x0f0f0f0f) << 4);
        rev = ((rev & 0xff00ff00) >> 8) | ((rev & 0x00ff00ff) << 8);
        rev = (rev >> 16) | (rev << 16);
        rev >>= shift;

        std::size_t j = rev;
        if (j > i)
        {
            std::swap(x[i], x[j]);
        }
    }

    // ---- Conjugate the result ----
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);
}
